import java.io.*;import java.util.*;class Main{static boolean canCross(int[]s){Map<Integer,Integer>pos=new HashMap<>();for(int i=0;i<s.length;i++)pos.put(s[i],i);List<Set<Integer>>dp=new ArrayList<>();for(int ignored:s)dp.add(new HashSet<>());dp.get(0).add(0);int last=s.length-1;for(int i=0;i<s.length;i++)for(int k:dp.get(i))for(int step:new int[]{k-1,k,k+1}){if(step<=0)continue;Integer j=pos.get(s[i]+step);if(j==null)continue;if(j==last)return true;dp.get(j).add(step);}return last==0;}public static void main(String[]a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){int n=Integer.parseInt(d[idx++]);int[]s=new int[n];for(int i=0;i<n;i++)s[i]=Integer.parseInt(d[idx++]);if(tc>0)out.append("\n\n");out.append(canCross(s)?"true":"false");}System.out.print(out);}}
